import os
from cryptography.fernet import Fernet

# Example application config holding the encryption key (use a secure storage in production)
APP_CONFIG = {
    "ENCRYPTION_KEY": Fernet.generate_key()
}

def encrypt_credit_card(card_number):
    f = Fernet(APP_CONFIG["ENCRYPTION_KEY"])
